            # Update existing item
            node = self.inventory[name]
            node.quantity = quantity
            node.price = price
            node.nutritional_info = nutritional_info
        else:
            # Add new item
            node = self.Node(name, quantity, price, nutritional_info)
            self.inventory[name] = node
            if self.head is None:
                self.head = node
            else:
                self.tail.next = node
                node.prev = self.tail
            self.tail = node

    def remove_item(self, name):
        if name not in self.inventory:
            return
        node = self.inventory[name]
        if node.prev is None:
            self.head = node.next
        else:
            node.prev.next = node.next
        if node.next is None:
            self.tail = node.prev
        else:
