class MyDictionary:
    def __init__(self):
        self.lookup = [None] * 1000  # Initialize list with None values
        self.indices = {}  # Initialize dictionary

    def add_entry(self, key, value):
        if not isinstance(key, int) or key <= 0 or key > 1000:
            raise ValueError("Key must be a positive integer between 1 and 1000")
        if not isinstance(value, str) or not value.islower() or not value:
            raise ValueError("Value must be a non-empty lowercase string")
        if key in self.indices:
            raise ValueError("Key already exists")

        index = len(self.indices)  # Get the next available index
        self.lookup[index] = value  # Add value to the list
        self.indices[key] = index  # Add key-index pair to the dictionary

    def get_value(self, key):
        index = self.indices.get(key)
        return self.lookup[index] if index is not None else None

    def update_value(self, key, new_value):
        if key in self.indices:
            index = self.indices[key]
            self.lookup[index] = new_value

    def remove_entry(self, key):
